import { TypeQuizQuestion } from "./quiz-types";
export const newQType7: TypeQuizQuestion[] = [
  // ── DIFFICULTY 1 (20 questions) ──
  { id: 1051, type: 7, difficulty: 1 as 1|2|3|4|5, track1Day: 1, track2Day: 51, category: "Real-Life Scenarios", question: "A Type 7 is stuck in a boring meeting. What are they most likely doing?", options: [{ letter: "A", text: "Taking meticulous notes" }, { letter: "B", text: "Mentally planning their weekend, doodling, or thinking of a way to make the meeting more interesting" }, { letter: "C", text: "Worrying about what could go wrong" }, { letter: "D", text: "Sitting patiently and quietly" }], answer: "B", explanation: "Sevens' minds are escape artists. When bored or uncomfortable, they automatically generate more stimulating alternatives. Their attention flies to the next exciting thing — planning, imagining, or finding creative ways to inject fun into dull situations." },
  { id: 1052, type: 7, difficulty: 1 as 1|2|3|4|5, track1Day: 2, track2Day: 52, category: "Real-Life Scenarios", question: "A Type 7 gets a flat tire on a road trip. Their reaction is:", options: [{ letter: "A", text: "Panic and call for help immediately" }, { letter: "B", text: "Reframe it as an adventure — 'At least we get to explore this town we'd never have stopped in!'" }, { letter: "C", text: "Become angry and blame someone" }, { letter: "D", text: "Sit quietly and wait" }], answer: "B", explanation: "Sevens are master reframers. They instinctively convert negative experiences into positive ones — not because they're in denial, but because their mind automatically seeks the silver lining as a defense against pain and limitation." },
  { id: 1053, type: 7, difficulty: 1 as 1|2|3|4|5, track1Day: 3, track2Day: 53, category: "Emotional Reactions", question: "When a Type 7 feels sad, they typically:", options: [{ letter: "A", text: "Sit with the sadness and process it fully" }, { letter: "B", text: "Quickly redirect to something fun, stimulating, or forward-looking — the sadness gets acknowledged briefly then escaped" }, { letter: "C", text: "Express it dramatically to everyone" }, { letter: "D", text: "Become angry instead" }], answer: "B", explanation: "Sevens process negative emotions like a hot potato: touch it briefly, then drop it. Their mind automatically generates distractions, plans, and positive reframes. This isn't superficiality — it's a deeply wired defense against the pain their system can't tolerate." },
  { id: 1054, type: 7, difficulty: 1 as 1|2|3|4|5, track1Day: 4, track2Day: 54, category: "Emotional Reactions", question: "A Type 7 cancels plans that they were excited about. How do they cope?", options: [{ letter: "A", text: "Grieve the lost plans" }, { letter: "B", text: "Immediately generate three alternative plans that are even more exciting" }, { letter: "C", text: "Become resentful toward whoever caused the cancellation" }, { letter: "D", text: "Accept it calmly without needing a replacement" }], answer: "B", explanation: "The Seven mind has a 'plan generator' that activates whenever options close. Lost Plan A? Here's Plan B, C, and D — each more exciting than the last. This rapid replacement prevents the disappointment from landing, keeping the Seven in their comfortable zone of anticipation." },
  { id: 1055, type: 7, difficulty: 1 as 1|2|3|4|5, track1Day: 5, track2Day: 55, category: "Type in Pop Culture", question: "Which fictional character best exemplifies the Type 7 pattern of enthusiasm, FOMO, and reframing pain?", options: [{ letter: "A", text: "Hermione Granger" }, { letter: "B", text: "The Genie from Aladdin" }, { letter: "C", text: "Batman" }, { letter: "D", text: "Eeyore from Winnie the Pooh" }], answer: "B", explanation: "The Genie is pure Seven energy: boundless enthusiasm, rapid-fire creativity, shape-shifting between ideas, entertaining constantly, and underneath it all, a hidden pain (being trapped) that gets covered with manic energy and humor." },
  { id: 1056, type: 7, difficulty: 1 as 1|2|3|4|5, track1Day: 6, track2Day: 56, category: "Type in Pop Culture", question: "Which character from The Office most displays Type 7 patterns of avoiding pain through fun and impulsiveness?", options: [{ letter: "A", text: "Dwight Schrute" }, { letter: "B", text: "Michael Scott" }, { letter: "C", text: "Angela Martin" }, { letter: "D", text: "Stanley Hudson" }], answer: "B", explanation: "Michael Scott is a Seven: desperate to keep things fun, terrified of being disliked or bored, impulsive, distractible, emotionally avoidant despite his apparent openness, and constantly reframing his failures as successes." },
  { id: 1057, type: 7, difficulty: 1 as 1|2|3|4|5, track1Day: 7, track2Day: 57, category: "Quick Identification", question: "Which phrase is most characteristic of a Type 7?", options: [{ letter: "A", text: "Let me think about this carefully" }, { letter: "B", text: "That sounds amazing — and then after that we could also do this other thing!" }, { letter: "C", text: "What's the responsible choice here?" }, { letter: "D", text: "I need time alone" }], answer: "B", explanation: "The Seven's signature is additive enthusiasm: every good idea spawns three more. Their 'and then!' energy builds excitement upon excitement, creating plans that multiply and branch into infinite possibilities." },
  { id: 1058, type: 7, difficulty: 1 as 1|2|3|4|5, track1Day: 8, track2Day: 58, category: "Quick Identification", question: "Which behavior most suggests someone is a Type 7?", options: [{ letter: "A", text: "Having a single deep hobby they've pursued for decades" }, { letter: "B", text: "Having started fifteen different hobbies in the past year, enthusiastic about each for weeks before moving to the next" }, { letter: "C", text: "Sticking to a rigid daily routine" }, { letter: "D", text: "Avoiding all social situations" }], answer: "B", explanation: "The Seven's hobby graveyard is legendary: guitar lessons, pottery class, rock climbing, French cooking, drone photography... Each one was 'the thing' until novelty faded and the next exciting option appeared. Depth is sacrificed for breadth." },
  { id: 1059, type: 7, difficulty: 1 as 1|2|3|4|5, track1Day: 9, track2Day: 59, category: "Common Phrases", question: "Which internal monologue is most typical for a Type 7?", options: [{ letter: "A", text: "What could go wrong?" }, { letter: "B", text: "What's next? What else could I experience? What am I missing out on?" }, { letter: "C", text: "Am I doing this perfectly?" }, { letter: "D", text: "Does this person need my help?" }], answer: "B", explanation: "The Seven's mind is a future-oriented anticipation machine. Their attention naturally races ahead to the next experience, creating the FOMO (fear of missing out) that drives their restless pursuit of stimulation." },
  { id: 1060, type: 7, difficulty: 1 as 1|2|3|4|5, track1Day: 10, track2Day: 60, category: "Common Phrases", question: "At a buffet, a Type 7 typically:", options: [{ letter: "A", text: "Chooses one thing and eats it methodically" }, { letter: "B", text: "Takes a small bit of everything because choosing one thing means missing out on the others" }, { letter: "C", text: "Asks the server what's healthiest" }, { letter: "D", text: "Waits to see what others choose first" }], answer: "B", explanation: "The buffet is the Seven's metaphor for life: unlimited options, and choosing one means closing others. They'd rather have a taste of everything than a full portion of one thing — breadth over depth, sampling over commitment." },
  { id: 1061, type: 7, difficulty: 1 as 1|2|3|4|5, track1Day: 11, track2Day: 61, category: "Childhood Patterns", question: "What childhood experience is most formative for Type 7s?", options: [{ letter: "A", text: "Being given everything they wanted" }, { letter: "B", text: "Experiencing pain, deprivation, or fear that they coped with by escaping into imagination, planning, and positive reframing" }, { letter: "C", text: "Being punished for being too quiet" }, { letter: "D", text: "Being the center of positive attention" }], answer: "B", explanation: "Sevens' optimism is a response to early pain. They learned that the mind could escape suffering through imagination, planning, and reframing. The defense was so effective that it became automatic — they forgot they were escaping because the escape became their identity." },
  { id: 1062, type: 7, difficulty: 1 as 1|2|3|4|5, track1Day: 12, track2Day: 62, category: "Childhood Patterns", question: "As children, Type 7s often:", options: [{ letter: "A", text: "Were quiet and obedient" }, { letter: "B", text: "Were the energizing, entertaining presence who kept everyone's spirits up — often using humor to deflect from family tension" }, { letter: "C", text: "Were serious and studious" }, { letter: "D", text: "Were isolated loners" }], answer: "B", explanation: "Young Sevens often become the family's entertainment system: the funny one, the bright one, the one who makes everyone feel better. Their humor and energy aren't just personality — they're a survival strategy that deflects from pain." },
  { id: 1063, type: 7, difficulty: 1 as 1|2|3|4|5, track1Day: 13, track2Day: 63, category: "Communication Style", question: "How does a Type 7 typically tell a story?", options: [{ letter: "A", text: "Linearly, with precise chronological details" }, { letter: "B", text: "In a spiraling, tangential way — one story reminds them of another, which reminds them of another, with enthusiastic detours and 'Oh, and also!'" }, { letter: "C", text: "Briefly and without elaboration" }, { letter: "D", text: "With emotional heaviness and dramatic pauses" }], answer: "B", explanation: "Seven storytelling is associative and additive: each detail sparks three tangents. They get excited by the connections their mind makes, often losing the original thread in a cascade of entertaining side stories. The journey IS the destination." },
  { id: 1064, type: 7, difficulty: 1 as 1|2|3|4|5, track1Day: 14, track2Day: 64, category: "Communication Style", question: "In conversations about difficult emotions, a Seven tends to:", options: [{ letter: "A", text: "Dive deep into the pain" }, { letter: "B", text: "Acknowledge the feeling briefly, then steer toward solutions, silver linings, or lighter topics" }, { letter: "C", text: "Become silent and withdrawn" }, { letter: "D", text: "Intellectualize the emotion" }], answer: "B", explanation: "Sevens have a short tolerance for emotional heaviness. They'll acknowledge sadness — 'That sucks, I'm sorry' — then quickly pivot: 'But here's what you could try...' or 'On the bright side...' They're trying to help, but the pivot also protects them from sitting in pain." },
  { id: 1065, type: 7, difficulty: 1 as 1|2|3|4|5, track1Day: 15, track2Day: 65, category: "Real-Life Scenarios", question: "A Type 7 has a free Saturday with no plans. They feel:", options: [{ letter: "A", text: "Peaceful and content" }, { letter: "B", text: "Anxious about wasting it — immediately brainstorming activities to fill the time with maximum experiences" }, { letter: "C", text: "Motivated to catch up on chores" }, { letter: "D", text: "Relieved to rest" }], answer: "B", explanation: "Empty time is terrifying for Sevens because it's un-stimulated time — time when uncomfortable thoughts or feelings might surface. They fill every gap with plans, options, and activities. An empty calendar is a Seven's existential threat." },
  { id: 1066, type: 7, difficulty: 1 as 1|2|3|4|5, track1Day: 16, track2Day: 66, category: "Emotional Reactions", question: "When a Seven's enthusiasm for a new project starts to fade, they typically:", options: [{ letter: "A", text: "Push through and finish it" }, { letter: "B", text: "Get excited about a newer, shinier project — leaving the old one incomplete" }, { letter: "C", text: "Become depressed" }, { letter: "D", text: "Blame others for making it boring" }], answer: "B", explanation: "The Seven's attention follows novelty like a compass follows north. When excitement wanes, their mind automatically generates the next thrilling possibility. The trail of unfinished projects isn't laziness — it's the Seven's nervous system chasing stimulation." },
  { id: 1067, type: 7, difficulty: 1 as 1|2|3|4|5, track1Day: 17, track2Day: 67, category: "Quick Identification", question: "Which vacation style most suggests a Seven?", options: [{ letter: "A", text: "A quiet beach resort with one book" }, { letter: "B", text: "An overloaded itinerary hitting every landmark, restaurant, and activity in the area" }, { letter: "C", text: "A structured guided tour" }, { letter: "D", text: "Staying home and relaxing" }], answer: "B", explanation: "Seven vacations are marathons of experience. They pack each day with activities because missing something feels worse than exhaustion. The fear isn't 'I might be tired' — it's 'I might miss something amazing.'" },
  { id: 1068, type: 7, difficulty: 1 as 1|2|3|4|5, track1Day: 18, track2Day: 68, category: "Common Phrases", question: "Which phrase reveals the Seven's relationship with commitment?", options: [{ letter: "A", text: "I'm all in, no matter what" }, { letter: "B", text: "I like to keep my options open" }, { letter: "C", text: "I've already decided" }, { letter: "D", text: "Whatever everyone else wants" }], answer: "B", explanation: "Keeping options open is the Seven's commitment strategy (or anti-strategy). Choosing one thing means closing off others, and closed options feel like small deaths. Open options = freedom = safety from the pain of limitation." },
  { id: 1069, type: 7, difficulty: 1 as 1|2|3|4|5, track1Day: 19, track2Day: 69, category: "Childhood Patterns", question: "Type 7 children often coped with family difficulty by:", options: [{ letter: "A", text: "Becoming very serious" }, { letter: "B", text: "Becoming the entertainer — making jokes, creating distractions, and keeping the mood light to protect themselves and others from pain" }, { letter: "C", text: "Withdrawing completely" }, { letter: "D", text: "Becoming highly organized" }], answer: "B", explanation: "The Seven child discovered that humor, energy, and positive spin could transform family tension. They became emotional alchemists — turning pain into play, sadness into silliness — and this magical trick became their lifelong strategy." },
  { id: 1070, type: 7, difficulty: 1 as 1|2|3|4|5, track1Day: 20, track2Day: 70, category: "Communication Style", question: "A Type 7's text messages typically feature:", options: [{ letter: "A", text: "Short, precise, minimal" }, { letter: "B", text: "Enthusiastic punctuation, rapid topic-hopping, links to things they've discovered, and invitations to do multiple things" }, { letter: "C", text: "Long emotional paragraphs" }, { letter: "D", text: "Delayed responses days later" }], answer: "B", explanation: "Seven texting is a stream of enthusiasm: 'OMG have you seen this?!' followed by 'Also we should try that restaurant!' followed by 'Oh and I had the best idea!' Each text branches into new possibilities. Their inbox is a garden of unfinished threads." },
  // ── DIFFICULTY 2 (20 questions) ──
  { id: 1071, type: 7, difficulty: 2 as 1|2|3|4|5, track1Day: 21, track2Day: 71, category: "Relationship Dynamics", question: "In romantic relationships, Type 7s are most at risk of:", options: [{ letter: "A", text: "Being too controlling" }, { letter: "B", text: "Emotional escapism — deflecting deep conversations, seeking novelty when the relationship feels routine, and confusing the excitement of new love with the depth of mature commitment" }, { letter: "C", text: "Being too clingy" }, { letter: "D", text: "Never having relationships" }], answer: "B", explanation: "Sevens in relationships can confuse the high of falling in love with love itself. When the novelty wears off, they may mistake the natural deepening phase for 'losing the spark' and unconsciously seek stimulation elsewhere — new flirtations, new projects, new distractions." },
  { id: 1072, type: 7, difficulty: 2 as 1|2|3|4|5, track1Day: 22, track2Day: 72, category: "Relationship Dynamics", question: "The Seven-Five pairing works because:", options: [{ letter: "A", text: "They're identical" }, { letter: "B", text: "The Five's depth and groundedness anchor the Seven's scattered energy, while the Seven's enthusiasm draws the Five out of their withdrawn fortress — each provides what the other lacks" }, { letter: "C", text: "They never argue" }, { letter: "D", text: "They're both highly social" }], answer: "B", explanation: "The 7-5 pairing creates complementary energy: the Seven provides enthusiasm, social warmth, and action that the Five needs but avoids; the Five provides depth, stillness, and focus that the Seven needs but resists. Each is medicine for the other's blind spot." },
  { id: 1073, type: 7, difficulty: 2 as 1|2|3|4|5, track1Day: 23, track2Day: 73, category: "Defense Mechanisms", question: "What is the primary defense mechanism of Type 7?", options: [{ letter: "A", text: "Projection" }, { letter: "B", text: "Rationalization — reframing negative experiences as positive, finding the silver lining in everything, and talking themselves out of pain through intellectual spin" }, { letter: "C", text: "Repression" }, { letter: "D", text: "Dissociation" }], answer: "B", explanation: "Sevens rationalize pain away: the breakup was 'meant to be,' the failure was 'a learning experience,' the loss 'opened new doors.' This isn't delusion — it's a sophisticated cognitive defense that transforms suffering into opportunity so fast the suffering never fully lands." },
  { id: 1074, type: 7, difficulty: 2 as 1|2|3|4|5, track1Day: 24, track2Day: 74, category: "Defense Mechanisms", question: "The Seven's 'gluttony' passion doesn't mean overeating. It means:", options: [{ letter: "A", text: "Eating too much food" }, { letter: "B", text: "An insatiable appetite for experience, stimulation, and possibilities — the compulsive consumption of life driven by the fear that what they have is never enough" }, { letter: "C", text: "Being materialistic" }, { letter: "D", text: "Hoarding objects" }], answer: "B", explanation: "Seven gluttony is experiential, not physical: they consume ideas, plans, experiences, and possibilities with the same voracity. The underlying fear: 'What I have right now isn't enough.' This creates the never-satisfied cycle that keeps them running from the present." },
  { id: 1075, type: 7, difficulty: 2 as 1|2|3|4|5, track1Day: 25, track2Day: 75, category: "Conflict Style", question: "How do Type 7s typically handle conflict?", options: [{ letter: "A", text: "With heavy emotional processing" }, { letter: "B", text: "By charming their way through it, reframing the issue positively, or simply shifting to a more pleasant topic — they'd rather negotiate than fight" }, { letter: "C", text: "With direct confrontation" }, { letter: "D", text: "By withdrawing completely" }], answer: "B", explanation: "Sevens disarm conflict with charm and reframing: 'Let's not fight about this — let's find a solution!' Their optimism can be genuinely helpful, but it can also prevent the deep processing that some conflicts require. Not everything can be reframed away." },
  { id: 1076, type: 7, difficulty: 2 as 1|2|3|4|5, track1Day: 26, track2Day: 76, category: "Conflict Style", question: "When a Seven can't escape a painful conversation, they:", options: [{ letter: "A", text: "Engage fully and deeply" }, { letter: "B", text: "Become visibly restless — fidgeting, eyes darting, mind racing for an exit — and may eventually become unexpectedly sharp or dismissive to end the discomfort" }, { letter: "C", text: "Become very quiet and contemplative" }, { letter: "D", text: "Start crying immediately" }], answer: "B", explanation: "Trapped in unavoidable pain, the Seven's exit strategies fail, and what emerges underneath is surprising: irritability, dismissiveness, or even cruelty. This isn't their nature — it's the panicked reaction of someone whose primary defense (escape) has been blocked." },
  { id: 1077, type: 7, difficulty: 2 as 1|2|3|4|5, track1Day: 27, track2Day: 77, category: "Shadow Work", question: "What is the Seven's deepest fear?", options: [{ letter: "A", text: "Being unsuccessful" }, { letter: "B", text: "Being trapped in pain, deprivation, or boredom — stuck in an unbearable present with no escape route to anything better" }, { letter: "C", text: "Being disliked" }, { letter: "D", text: "Being wrong" }], answer: "B", explanation: "The Seven's existential terror is being trapped in suffering with no exit. This is why they keep options open, plans multiplying, and exits available. Commitment, limitation, and being stuck represent the claustrophobia of inescapable pain." },
  { id: 1078, type: 7, difficulty: 2 as 1|2|3|4|5, track1Day: 28, track2Day: 78, category: "Shadow Work", question: "The Seven's 'monkey mind' pattern refers to:", options: [{ letter: "A", text: "Being unintelligent" }, { letter: "B", text: "A mind that swings from thought to thought, plan to plan, idea to idea — never resting, always anticipating — as a defense against the stillness where pain might surface" }, { letter: "C", text: "Being playful" }, { letter: "D", text: "Physical restlessness only" }], answer: "B", explanation: "The Seven's mind is in perpetual motion: planning, anticipating, generating. This isn't ADHD (though they can co-occur) — it's a defense system. The mind stays busy because stillness brings contact with the present moment, which might contain the pain they're avoiding." },
  { id: 1079, type: 7, difficulty: 2 as 1|2|3|4|5, track1Day: 29, track2Day: 79, category: "Parenting Style", question: "Type 7 parents are most likely to:", options: [{ letter: "A", text: "Be strict disciplinarians" }, { letter: "B", text: "Be the 'fun parent' who creates amazing experiences but may struggle with discipline, follow-through, and sitting with their children's painful emotions" }, { letter: "C", text: "Be emotionally unavailable" }, { letter: "D", text: "Focus exclusively on academics" }], answer: "B", explanation: "Seven parents create magical childhoods: adventures, surprises, creativity, and fun. Their challenge is the non-fun parts: enforcing limits, sitting with a crying child without fixing it, and tolerating the boring repetition that parenting requires." },
  { id: 1080, type: 7, difficulty: 2 as 1|2|3|4|5, track1Day: 30, track2Day: 80, category: "Attachment Style", question: "Which attachment style is most common among Type 7s?", options: [{ letter: "A", text: "Anxious-preoccupied" }, { letter: "B", text: "Dismissive-avoidant or secure-appearing — they seem easy and flexible in relationships while subtly maintaining emotional escape routes" }, { letter: "C", text: "Fearful-avoidant" }, { letter: "D", text: "Deeply enmeshed" }], answer: "B", explanation: "Sevens often appear securely attached because they're pleasant, easy-going, and non-clingy. But underneath, they maintain emotional distance through distraction and option-keeping. Their avoidance is disguised by their warmth — the friendliest exit strategy in the Enneagram." },
  { id: 1081, type: 7, difficulty: 2 as 1|2|3|4|5, track1Day: 31, track2Day: 81, category: "Somatic Patterns", question: "Where do Type 7s most commonly experience anxiety in their body?", options: [{ letter: "A", text: "Heavy, grounded sensations" }, { letter: "B", text: "Restless energy in the limbs, shallow breathing, and a buzzing, up-in-the-head sensation — their energy rises rather than grounds" }, { letter: "C", text: "Stomach pain" }, { letter: "D", text: "Lower back tension" }], answer: "B", explanation: "Seven anxiety manifests as upward, scattered energy: fidgety limbs, shallow breath, racing thoughts. Their energy rises into the head (planning, imagining) rather than grounding into the body. This somatic pattern mirrors their psychological escape from embodied, present-moment experience." },
  { id: 1082, type: 7, difficulty: 2 as 1|2|3|4|5, track1Day: 32, track2Day: 82, category: "Somatic Patterns", question: "Sevens often have difficulty with:", options: [{ letter: "A", text: "High energy" }, { letter: "B", text: "Slowing down enough to notice their body's signals — they override fatigue, hunger, and pain signals because paying attention to the body means being in the present moment" }, { letter: "C", text: "Too much relaxation" }, { letter: "D", text: "Physical fitness" }], answer: "B", explanation: "Sevens override bodily signals because the body lives in the now, and the Seven lives in the next. They may not notice they're exhausted, hungry, or in pain until the body forces attention — through illness, injury, or collapse." },
  { id: 1083, type: 7, difficulty: 2 as 1|2|3|4|5, track1Day: 33, track2Day: 83, category: "Coping Under Stress", question: "When stressed, Type 7s move toward which type's behaviors?", options: [{ letter: "A", text: "Type 4 — becoming dramatic and emotional" }, { letter: "B", text: "Type 1 — becoming critical, rigid, perfectionistic, and suddenly focused on what's wrong instead of what's exciting" }, { letter: "C", text: "Type 8 — becoming aggressive" }, { letter: "D", text: "Type 9 — becoming passive" }], answer: "B", explanation: "Under stress, Sevens disintegrate to One: the fun-loving free spirit becomes a nitpicking perfectionist. They become critical of themselves and others, rigid about 'the right way,' and suddenly focused on problems instead of possibilities. It's a jarring personality shift." },
  { id: 1084, type: 7, difficulty: 2 as 1|2|3|4|5, track1Day: 34, track2Day: 84, category: "Coping Under Stress", question: "What does healthy growth look like for a Type 7?", options: [{ letter: "A", text: "Having more experiences" }, { letter: "B", text: "Moving toward Type 5 qualities: depth over breadth, focus over scatter, and the ability to be present with one thing fully rather than sampling everything lightly" }, { letter: "C", text: "Becoming more spontaneous" }, { letter: "D", text: "Traveling more" }], answer: "B", explanation: "In growth, Sevens integrate to Five: the scattered butterfly becomes focused and deep. They learn to stay with one subject, one person, one feeling long enough to truly know it. Depth replaces breadth, and presence replaces anticipation." },
  { id: 1085, type: 7, difficulty: 2 as 1|2|3|4|5, track1Day: 35, track2Day: 85, category: "Workplace Archetypes", question: "Which workplace role does a Type 7 most naturally gravitate toward?", options: [{ letter: "A", text: "Detail-oriented quality control" }, { letter: "B", text: "The visionary idea-generator, brainstormer, or innovative role where new concepts and creative possibilities are valued" }, { letter: "C", text: "The quiet analyst" }, { letter: "D", text: "The process enforcer" }], answer: "B", explanation: "Sevens excel in roles that value idea-generation, creativity, and vision. They're the brainstorm champions, the innovation leads, the ones who see possibilities no one else imagined. Their challenge: following through on ideas long enough for them to become reality." },
  { id: 1086, type: 7, difficulty: 2 as 1|2|3|4|5, track1Day: 36, track2Day: 86, category: "Workplace Archetypes", question: "A Seven's biggest workplace blind spot is:", options: [{ letter: "A", text: "Lack of ideas" }, { letter: "B", text: "Follow-through — they generate brilliant ideas but struggle to execute them because the implementation phase is less exciting than the conception phase" }, { letter: "C", text: "Being too detail-oriented" }, { letter: "D", text: "Lack of social skills" }], answer: "B", explanation: "Sevens are idea machines with implementation allergies. The exciting part (brainstorming, planning, possibilities) gets all their energy; the boring part (executing, maintaining, debugging) gets abandoned for the next exciting thing. Many great Seven ideas die in the implementation gap." },
  { id: 1087, type: 7, difficulty: 2 as 1|2|3|4|5, track1Day: 37, track2Day: 87, category: "Relationship Dynamics", question: "What makes Type 7s exceptional partners when healthy?", options: [{ letter: "A", text: "Their seriousness" }, { letter: "B", text: "Their ability to bring joy, adventure, and lightness to daily life — making the mundane magical and helping their partner see possibilities where they once saw limitations" }, { letter: "C", text: "Their strict boundaries" }, { letter: "D", text: "Their predictability" }], answer: "B", explanation: "Healthy Sevens are relationship alchemists: they transform ordinary Tuesdays into adventures, find humor in frustration, and remind their partners that life is full of wonder. Their enthusiasm is contagious, and their optimism provides genuine uplift." },
  { id: 1088, type: 7, difficulty: 2 as 1|2|3|4|5, track1Day: 38, track2Day: 88, category: "Defense Mechanisms", question: "The Seven's 'future tripping' pattern means:", options: [{ letter: "A", text: "Planning vacations" }, { letter: "B", text: "Living in anticipation of future experiences rather than in the present — the excitement of what's coming substitutes for the richness of what's happening now" }, { letter: "C", text: "Worrying about the future" }, { letter: "D", text: "Setting career goals" }], answer: "B", explanation: "Sevens live in anticipation: the upcoming trip is more exciting than the current one, the next project more thrilling than the present one. Anticipation becomes a drug — the dopamine of 'soon' replaces the deeper satisfaction of 'now.'" },
  { id: 1089, type: 7, difficulty: 2 as 1|2|3|4|5, track1Day: 39, track2Day: 89, category: "Shadow Work", question: "The Seven's hidden depression is:", options: [{ letter: "A", text: "Nonexistent" }, { letter: "B", text: "A deep well of sadness and pain they've been running from their entire life — buried under layers of optimism, activity, and distraction, waiting to surface when the running finally stops" }, { letter: "C", text: "Identical to everyone else's" }, { letter: "D", text: "Purely physical" }], answer: "B", explanation: "Behind every manic Seven is a depression they're outrunning. The whole structure — the plans, the optimism, the restless activity — was built as a fortress against inner pain. When life forces the Seven to stop (illness, loss, crisis), the buried grief surfaces with devastating force." },
  { id: 1090, type: 7, difficulty: 2 as 1|2|3|4|5, track1Day: 40, track2Day: 90, category: "Childhood Patterns", question: "The Seven's 'frustration of nurturing' wound means:", options: [{ letter: "A", text: "They were never frustrated" }, { letter: "B", text: "They experienced a premature or abrupt loss of nurturing (emotional or physical), leading to the conclusion: 'If I can't count on being taken care of, I'll take care of myself by making sure I never need anything'" }, { letter: "C", text: "They had too much nurturing" }, { letter: "D", text: "Their parents were perfect" }], answer: "B", explanation: "Many Sevens experienced an early disruption of nurturing: a parent who left, a sudden emotional unavailability, or a childhood that ended too soon. They adapted by becoming self-sufficient pleasure-seekers: 'I don't need you — I'll create my own joy.'" },
  // ── DIFFICULTY 3 (20 questions) ──
  { id: 1091, type: 7, difficulty: 3 as 1|2|3|4|5, track1Day: 41, track2Day: 91, category: "Spiritual Traditions", question: "In contemplative traditions, the Seven's growth path involves:", options: [{ letter: "A", text: "More exciting spiritual experiences" }, { letter: "B", text: "Practices of staying present — meditation, silence, and single-pointed focus that interrupt the escape mechanism and reveal that the present moment contains everything they've been seeking" }, { letter: "C", text: "Studying more traditions" }, { letter: "D", text: "Spiritual tourism" }], answer: "B", explanation: "Sevens need practices that pin them to the present: focused meditation, silent retreat, single-task attention. These feel like imprisonment initially but gradually reveal the paradox: the richness they've been chasing is available right here, in this moment, without going anywhere." },
  { id: 1092, type: 7, difficulty: 3 as 1|2|3|4|5, track1Day: 42, track2Day: 92, category: "Spiritual Traditions", question: "The Buddhist concept of 'right effort' challenges the Seven because:", options: [{ letter: "A", text: "Sevens are lazy" }, { letter: "B", text: "It means neither too much effort (the Seven's overactive mind) nor too little (what they fear), but precisely the amount needed — which requires staying with rather than escaping from the present moment" }, { letter: "C", text: "They don't like Buddhism" }, { letter: "D", text: "They already have perfect effort" }], answer: "B", explanation: "Right effort for a Seven means learning to do less, not more. Their default is over-efforting through stimulation. Buddhist 'right effort' asks them to find the middle way between manic doing and the stillness they fear — an uncomfortable but liberating balance." },
  { id: 1093, type: 7, difficulty: 3 as 1|2|3|4|5, track1Day: 43, track2Day: 93, category: "Enneagram x MBTI", question: "How does a Type 7 ENFP differ from a Type 7 ESTP?", options: [{ letter: "A", text: "They're identical" }, { letter: "B", text: "The ENFP Seven generates possibilities through imagination and meaning-making; the ESTP Seven generates possibilities through physical action and sensory adventure" }, { letter: "C", text: "Only ENFPs can be Sevens" }, { letter: "D", text: "ESTPs are less adventurous" }], answer: "B", explanation: "Same core motivation (avoiding pain through stimulation), different vehicles. ENFP Sevens are idea-Sevens: they seek novelty through brainstorming, visioning, and creative connection. ESTP Sevens are action-Sevens: they seek novelty through physical adventure, risk, and sensory experience." },
  { id: 1094, type: 7, difficulty: 3 as 1|2|3|4|5, track1Day: 44, track2Day: 94, category: "Enneagram x MBTI", question: "A Type 7 INTJ is unusual because:", options: [{ letter: "A", text: "It doesn't exist" }, { letter: "B", text: "The INTJ's strategic focus and depth combines with the Seven's enthusiasm and breadth — creating someone who generates many ideas but also has the strategic capacity to develop the best ones" }, { letter: "C", text: "Sevens are always extroverts" }, { letter: "D", text: "INTJs don't have fun" }], answer: "B", explanation: "7-INTJ bridges the Seven's breadth and the INTJ's depth. These Sevens are more focused and strategic than typical — they still generate many possibilities but have the Ni-Te infrastructure to evaluate and implement the best ones. Visionary planners rather than scatter-shot enthusiasts." },
  { id: 1095, type: 7, difficulty: 3 as 1|2|3|4|5, track1Day: 45, track2Day: 95, category: "Instinct x Wing Combos", question: "How does a Social Seven (SO7) differ from the stereotypical Seven?", options: [{ letter: "A", text: "They're identical" }, { letter: "B", text: "SO7 is the counter-type — they channel gluttony into service and sacrifice for the group, appearing selfless and anti-hedonistic while still avoiding their own pain by focusing on the collective" }, { letter: "C", text: "SO7s are antisocial" }, { letter: "D", text: "SO7s are more indulgent" }], answer: "B", explanation: "SO7 is the counter-type: they look un-Seven-like because their gluttony manifests as excessive giving rather than taking. They sacrifice for the group, appear idealistic and selfless, but are still running from their own pain — into the needs of others instead of into personal pleasure." },
  { id: 1096, type: 7, difficulty: 3 as 1|2|3|4|5, track1Day: 46, track2Day: 96, category: "Instinct x Wing Combos", question: "A Sexual (SX) Seven is characterized by:", options: [{ letter: "A", text: "Calm contentment" }, { letter: "B", text: "Seeking an idealized world of wonder — they're dreamers who see the world through rose-colored glasses, seeking the ultimate experience of beauty, love, or transcendence" }, { letter: "C", text: "Practical materialism" }, { letter: "D", text: "Social conformity" }], answer: "B", explanation: "SX Sevens are the most romantic and idealistic. Their gluttony focuses on the transcendent experience — the perfect love, the ultimate beauty, the mystical encounter. They're the dreamer-poets of the Seven world, seeing magic everywhere." },
  { id: 1097, type: 7, difficulty: 3 as 1|2|3|4|5, track1Day: 47, track2Day: 97, category: "Tritype Deep Dives", question: "The 729 tritype ('The Peacemaker') creates what kind of Seven?", options: [{ letter: "A", text: "The most aggressive Seven" }, { letter: "B", text: "The sweetest, most conflict-averse Seven — they use optimism and pleasantness to maintain harmony, avoiding both their own pain and others' conflict" }, { letter: "C", text: "The most intellectual Seven" }, { letter: "D", text: "The most ambitious Seven" }], answer: "B", explanation: "The 729 combines Seven's optimism with Two's warmth and Nine's peace-seeking. This creates the most pleasant Seven variant: agreeable, helpful, and sunny — but potentially the most avoidant, using niceness as a triple-layered defense against any form of discomfort." },
  { id: 1098, type: 7, difficulty: 3 as 1|2|3|4|5, track1Day: 48, track2Day: 98, category: "Tritype Deep Dives", question: "The 748 tritype ('The Maverick') combines:", options: [{ letter: "A", text: "Quietness and restraint" }, { letter: "B", text: "Seven's vision with Four's creative depth and Eight's forcefulness — creating a bold, original, take-no-prisoners innovator who pushes boundaries with intensity" }, { letter: "C", text: "Caution and modesty" }, { letter: "D", text: "Conformity and tradition" }], answer: "B", explanation: "The 748 is the most intense Seven tritype: Seven brings the vision, Four brings the creative depth, and Eight brings the power. This person doesn't just have big ideas — they bulldoze obstacles to make them real. Think visionary entrepreneurs who break every mold." },
  { id: 1099, type: 7, difficulty: 3 as 1|2|3|4|5, track1Day: 49, track2Day: 99, category: "Growth Practices", question: "Why is 'completing one thing before starting the next' a growth practice for Sevens?", options: [{ letter: "A", text: "It builds their resume" }, { letter: "B", text: "It teaches them that depth and follow-through create a richer satisfaction than the temporary thrill of starting new things — and that they can survive the non-exciting phases" }, { letter: "C", text: "It doesn't help them" }, { letter: "D", text: "It makes them more boring" }], answer: "B", explanation: "Completion is the Seven's spiritual practice. Staying with one thing through the boring middle teaches them that the deeper reward of mastery surpasses the shallow thrill of novelty. And they survive the tedium — which proves their fear of boredom was exaggerated." },
  { id: 1100, type: 7, difficulty: 3 as 1|2|3|4|5, track1Day: 50, track2Day: 100, category: "Growth Practices", question: "The practice of 'sitting with pain without reframing it' challenges Sevens because:", options: [{ letter: "A", text: "They enjoy pain" }, { letter: "B", text: "Their entire defense system is built on converting pain to positivity — allowing pain to remain painful, without silver-lining it, feels like dismantling their survival mechanism" }, { letter: "C", text: "They already sit with pain" }, { letter: "D", text: "Pain is always destructive" }], answer: "B", explanation: "Ask a Seven to say 'This hurts and there's nothing good about it' — and their entire system rebels. The reframe generator fires up: 'But at least...' 'What I learned was...' Sitting with unspun pain is the Seven's deepest growth edge because it directly confronts their core defense." },
  { id: 1101, type: 7, difficulty: 3 as 1|2|3|4|5, track1Day: 1, track2Day: 51, category: "Naranjo's Character Types", question: "Claudio Naranjo described the Seven as:", options: [{ letter: "A", text: "The Loyalist" }, { letter: "B", text: "The 'charlatan' or 'strategic optimist' — someone who has become so skilled at reframing reality that they've convinced themselves their substitute world is the real one" }, { letter: "C", text: "The Perfectionist" }, { letter: "D", text: "The Peacemaker" }], answer: "B", explanation: "Naranjo saw the Seven as a reality-editor: they reconstruct experience so effectively that the edited version becomes their truth. The 'charlatan' label isn't about dishonesty but about the remarkable skill of self-deception through optimistic rationalization." },
  { id: 1102, type: 7, difficulty: 3 as 1|2|3|4|5, track1Day: 2, track2Day: 52, category: "Panel Wisdom", question: "In Enneagram panels, Type 7s commonly report:", options: [{ letter: "A", text: "Always feeling deeply fulfilled" }, { letter: "B", text: "The shock of realizing that their 'positivity' was actually a form of emotional avoidance — that their sunny exterior was built on top of unfelt grief they'd been outrunning for decades" }, { letter: "C", text: "Having no shadow side" }, { letter: "D", text: "Being naturally deep" }], answer: "B", explanation: "The Seven's panel breakthrough is often the most dramatic: the realization that their defining trait (positivity) was actually their deepest defense. Seeing their sunshine as a strategy for avoiding shadows is devastating but liberating — it opens the door to genuine, rather than manufactured, joy." },
  { id: 1103, type: 7, difficulty: 3 as 1|2|3|4|5, track1Day: 3, track2Day: 53, category: "Differential Diagnosis", question: "How do you distinguish a Type 7 from a Type 3?", options: [{ letter: "A", text: "They're the same type" }, { letter: "B", text: "Threes do things to be admired; Sevens do things to be stimulated — the Three asks 'How does this look?' while the Seven asks 'How does this feel?'" }, { letter: "C", text: "Sevens are more ambitious" }, { letter: "D", text: "Threes have more fun" }], answer: "B", explanation: "Both types are energetic and achievement-oriented, but for different reasons. Threes achieve for image (external validation). Sevens experience for stimulation (internal satisfaction). A Three will do boring things that look impressive; a Seven won't." },
  { id: 1104, type: 7, difficulty: 3 as 1|2|3|4|5, track1Day: 4, track2Day: 54, category: "Differential Diagnosis", question: "A person is enthusiastic, future-focused, and avoids negative emotions. Could be a 7 or a 9. The differentiator is:", options: [{ letter: "A", text: "They're the same" }, { letter: "B", text: "Sevens are energetically up and forward — actively pursuing stimulation; Nines are energetically settled and neutral — passively merging with comfort. The Seven runs from pain into excitement; the Nine numbs away from pain into comfort" }, { letter: "C", text: "Nines are more enthusiastic" }, { letter: "D", text: "Sevens are calmer" }], answer: "B", explanation: "Both types avoid negative emotions, but with opposite energy: Sevens escape UP (into excitement, plans, stimulation) while Nines escape DOWN (into comfort, routine, numbness). The Seven's avoidance is active and energized; the Nine's is passive and tranquilized." },
  { id: 1105, type: 7, difficulty: 3 as 1|2|3|4|5, track1Day: 5, track2Day: 55, category: "Workplace Archetypes", question: "A Seven with a 6-wing (7w6) in the workplace:", options: [{ letter: "A", text: "Is purely impulsive" }, { letter: "B", text: "Combines enthusiasm with more groundedness and team loyalty — they're the creative idea-person who also cares about the team and can assess risks alongside opportunities" }, { letter: "C", text: "Avoids all teamwork" }, { letter: "D", text: "Is purely cautious" }], answer: "B", explanation: "7w6 adds Six's loyalty and risk-awareness to Seven's enthusiasm. They're more grounded than pure Sevens: creative and optimistic but also team-oriented and able to spot potential problems. This makes them more implementable visionaries." },
  { id: 1106, type: 7, difficulty: 3 as 1|2|3|4|5, track1Day: 6, track2Day: 56, category: "Workplace Archetypes", question: "A Seven with an 8-wing (7w8) in the workplace:", options: [{ letter: "A", text: "Is shy and cautious" }, { letter: "B", text: "Combines vision with force — they don't just generate ideas, they push them through with assertive energy, creating a bold, sometimes overwhelming entrepreneurial presence" }, { letter: "C", text: "Avoids all leadership" }, { letter: "D", text: "Is purely analytical" }], answer: "B", explanation: "7w8 adds Eight's forcefulness to Seven's vision. They're the most powerful Seven variant: they see the exciting possibility AND have the willpower to make it happen. Think startup founders, bold directors, or any leader who combines vision with aggressive execution." },
  { id: 1107, type: 7, difficulty: 3 as 1|2|3|4|5, track1Day: 7, track2Day: 57, category: "Coping Under Stress", question: "The Seven's disintegration to One often surprises those around them because:", options: [{ letter: "A", text: "It's not surprising" }, { letter: "B", text: "The normally fun, flexible, easygoing Seven suddenly becomes critical, rigid, and perfectionistic — the polar opposite of their usual personality" }, { letter: "C", text: "They become more fun" }, { letter: "D", text: "They become quieter" }], answer: "B", explanation: "Seven → One disintegration is one of the most dramatic personality shifts: the adventurous optimist becomes a tight-lipped perfectionist. Partners are baffled: 'Where did the fun person go?' The answer: they're stressed beyond their coping capacity, and the backup system (One-ish control) has activated." },
  { id: 1108, type: 7, difficulty: 3 as 1|2|3|4|5, track1Day: 8, track2Day: 58, category: "Communication Style", question: "The Seven's 'yes, and...' communication pattern means:", options: [{ letter: "A", text: "They agree with everything" }, { letter: "B", text: "They build on every idea additively — rather than filtering or narrowing, they expand possibilities, which makes brainstorming brilliant but decision-making difficult" }, { letter: "C", text: "They're trained improvisers" }, { letter: "D", text: "They can't say no" }], answer: "B", explanation: "Sevens are natural improv artists: every idea spawns a 'yes, and...' The problem is that options only multiply, never narrow. Making a decision requires killing options — which feels like small deaths to a Seven. So options accumulate without resolution." },
  { id: 1109, type: 7, difficulty: 3 as 1|2|3|4|5, track1Day: 9, track2Day: 59, category: "Emotional Reactions", question: "Sevens are often described as 'sunny with a shadow' because:", options: [{ letter: "A", text: "They like sunbathing" }, { letter: "B", text: "Their bright, enthusiastic exterior conceals a depth of pain that's inversely proportional to their positivity — the brighter the sunshine, the deeper the shadow it's covering" }, { letter: "C", text: "They're always in a good mood" }, { letter: "D", text: "They don't have a shadow" }], answer: "B", explanation: "The Seven's positivity is load-bearing: it's supporting the weight of all the unfelt grief, fear, and pain they've pushed underground. The more relentlessly positive a Seven appears, the more likely there's a significant shadow being managed." },
  { id: 1110, type: 7, difficulty: 3 as 1|2|3|4|5, track1Day: 10, track2Day: 60, category: "Relationship Dynamics", question: "The Seven's 'commitment avoidance' in relationships stems from:", options: [{ letter: "A", text: "Not caring about people" }, { letter: "B", text: "The fear that commitment means choosing one path and closing all others — and closed paths represent the limitation and potential pain they've built their entire life around avoiding" }, { letter: "C", text: "Being too busy" }, { letter: "D", text: "Having too many friends" }], answer: "B", explanation: "Seven commitment resistance isn't about not caring — it's about the terror of limitation. Choosing one partner means accepting that other possibilities die. The Seven's nervous system registers this as: 'You're trapped now.' And being trapped is the Seven's core nightmare." },
  // ── DIFFICULTY 4 (20 questions) ──
  { id: 1111, type: 7, difficulty: 4 as 1|2|3|4|5, track1Day: 41, track2Day: 91, category: "Ichazo Fixations", question: "Oscar Ichazo named the Seven's fixation 'planning.' In his framework, this means:", options: [{ letter: "A", text: "Being organized" }, { letter: "B", text: "The cognitive habit of perpetually anticipating future pleasure as a substitute for present-moment experience — the mind lives in the map of the future rather than the territory of the now" }, { letter: "C", text: "Setting goals" }, { letter: "D", text: "Strategic thinking" }], answer: "B", explanation: "Ichazo's 'planning' isn't productivity — it's anticipatory escapism. The Seven's mind generates future scenarios as a substitute for being here now. The plan IS the experience; the anticipation IS the pleasure. This makes the present perpetually disappointing compared to the imagined future." },
  { id: 1112, type: 7, difficulty: 4 as 1|2|3|4|5, track1Day: 42, track2Day: 92, category: "Ichazo Fixations", question: "The Seven's holy idea in Ichazo's system is 'Holy Wisdom' (or 'Holy Plan'). This means:", options: [{ letter: "A", text: "They should plan more" }, { letter: "B", text: "The recognition that reality unfolds in a natural, supportive pattern — there's a wisdom in things as they are that doesn't need to be improved through escape or reframing" }, { letter: "C", text: "They should be wiser" }, { letter: "D", text: "God has a plan" }], answer: "B", explanation: "Holy Wisdom (or Holy Work) teaches Sevens that the natural unfolding of reality IS the plan — it doesn't need to be escaped, improved, or supplemented with fantasies. The present moment is already perfect, containing everything they need without the mind's additions." },
  { id: 1113, type: 7, difficulty: 4 as 1|2|3|4|5, track1Day: 43, track2Day: 93, category: "Object Relations Deep", question: "In object relations theory, the Seven's developmental challenge relates to:", options: [{ letter: "A", text: "Too much frustration" }, { letter: "B", text: "The 'depressive position' — where one must accept that good and bad coexist in the same object; the Seven refuses this integration, splitting off the bad to maintain an idealized, all-good reality" }, { letter: "C", text: "Excessive mirroring" }, { letter: "D", text: "Oedipal conflict" }], answer: "B", explanation: "Klein's depressive position requires accepting ambivalence: good and bad are mixed. Sevens remain in the 'paranoid-schizoid position': they split off the bad (pain, limitation) to preserve the all-good (pleasure, possibility). Integration means accepting that life includes both." },
  { id: 1114, type: 7, difficulty: 4 as 1|2|3|4|5, track1Day: 44, track2Day: 94, category: "Object Relations Deep", question: "The Seven's relationship to the 'good object' in object relations is:", options: [{ letter: "A", text: "Normal" }, { letter: "B", text: "They idealize the good object and desperately protect it from contamination by the bad — this is why they reframe negatives, flee pain, and maintain optimism: the good must be preserved at all costs" }, { letter: "C", text: "They reject all good objects" }, { letter: "D", text: "They don't have internal objects" }], answer: "B", explanation: "Sevens protect the internalized good object (the exciting, pleasurable world) with fierce determination. Any bad experience threatens to contaminate this idealized internal world, so it must be reframed, escaped, or denied. The defense preserves inner paradise at the cost of reality." },
  { id: 1115, type: 7, difficulty: 4 as 1|2|3|4|5, track1Day: 45, track2Day: 95, category: "Counter-Instinctual Combos", question: "Why is the SO7 considered the most counter-instinctual Seven?", options: [{ letter: "A", text: "They're the most indulgent" }, { letter: "B", text: "Their gluttony manifests as excessive sacrifice for the group — they feel guilty about personal pleasure and redirect their appetite into service, appearing selfless while still avoiding their own inner pain" }, { letter: "C", text: "They're identical to other Sevens" }, { letter: "D", text: "They're antisocial" }], answer: "B", explanation: "SO7 is the anti-gluttony Seven: they give instead of take, sacrifice instead of indulge, and serve the group instead of pursuing personal pleasure. But the mechanism is the same — they're still running from their pain, just running into altruism instead of hedonism." },
  { id: 1116, type: 7, difficulty: 4 as 1|2|3|4|5, track1Day: 46, track2Day: 96, category: "Counter-Instinctual Combos", question: "An SP7 is the most 'typically Seven' because:", options: [{ letter: "A", text: "Random convention" }, { letter: "B", text: "The self-preservation instinct amplifies the Seven's appetite for sensory pleasure — they're the most visibly hedonistic, seeking comfort, variety, and material enjoyment as their primary pain-avoidance strategy" }, { letter: "C", text: "They're the rarest" }, { letter: "D", text: "They're the least Seven-like" }], answer: "B", explanation: "SP7 most closely matches the Seven stereotype: food, comfort, variety, pleasure-seeking, and a relentless drive for new sensory experiences. Their self-preservation instinct channels gluttony into tangible, physical forms — the most visible expression of Seven energy." },
  { id: 1117, type: 7, difficulty: 4 as 1|2|3|4|5, track1Day: 47, track2Day: 97, category: "Historical Enneagram", question: "The Seven's position in the Enneagram as the 'forward-moving' Head type means:", options: [{ letter: "A", text: "They're the most intellectual" }, { letter: "B", text: "They manage fear by moving toward positive future scenarios — while the Five retreats from fear into knowledge and the Six stays with fear in doubt, the Seven outruns fear through optimistic planning" }, { letter: "C", text: "They're always moving physically" }, { letter: "D", text: "They don't experience fear" }], answer: "B", explanation: "Each Head type manages fear differently: Five retreats backward (into knowledge), Six stays in place (in doubt), Seven moves forward (into plans). The Seven's strategy is flight — specifically, flight into the future, where things are always better than the present." },
  { id: 1118, type: 7, difficulty: 4 as 1|2|3|4|5, track1Day: 48, track2Day: 98, category: "Historical Enneagram", question: "In Riso and Hudson's Levels of Development, a healthy Level 1-3 Seven manifests as:", options: [{ letter: "A", text: "More hedonistic" }, { letter: "B", text: "Deeply grateful, present, and joyful — their enthusiasm becomes genuine appreciation for what IS rather than restless pursuit of what could be" }, { letter: "C", text: "More scattered" }, { letter: "D", text: "Less creative" }], answer: "B", explanation: "Healthy Sevens are among the most joyful people alive — not from escaping pain but from genuinely appreciating the present. Their gratitude is real, their presence is deep, and their enthusiasm comes from fullness rather than from running on empty." },
  { id: 1119, type: 7, difficulty: 4 as 1|2|3|4|5, track1Day: 49, track2Day: 99, category: "Integration/Disintegration Chains", question: "When a Seven disintegrates to One, the internal experience is:", options: [{ letter: "A", text: "Relief" }, { letter: "B", text: "The inner critic — normally silenced by optimism — breaks through the defenses and attacks mercilessly, creating the perfectionism, rigidity, and self-criticism the Seven usually avoids" }, { letter: "C", text: "Increased fun" }, { letter: "D", text: "Emotional numbness" }], answer: "B", explanation: "Seven → One disintegration is the inner critic's revenge: the voice the Seven has been drowning out with positivity and plans finally breaks through. Suddenly they're self-critical, perfectionistic, and judgmental — the shadow of their optimism emerging as its opposite." },
  { id: 1120, type: 7, difficulty: 4 as 1|2|3|4|5, track1Day: 50, track2Day: 100, category: "Integration/Disintegration Chains", question: "When a Seven integrates to Five, the specific transformation involves:", options: [{ letter: "A", text: "Becoming boring" }, { letter: "B", text: "Discovering the profound satisfaction of depth — going deep into one subject, one relationship, one moment, and finding more richness there than in a thousand surface-level samplings" }, { letter: "C", text: "Losing their creativity" }, { letter: "D", text: "Becoming isolated" }], answer: "B", explanation: "Five-integration gives Sevens what they most need: the ability to go deep. They discover that one profound experience surpasses a hundred shallow ones. Quality replaces quantity. The present moment, fully inhabited, contains more than any future plan could promise." },
  { id: 1121, type: 7, difficulty: 4 as 1|2|3|4|5, track1Day: 1, track2Day: 51, category: "Naranjo's Character Types", question: "Naranjo identified that the Seven's optimism serves as:", options: [{ letter: "A", text: "Pure positivity" }, { letter: "B", text: "A sophisticated avoidance mechanism — the most socially rewarded form of emotional escapism, which is why Sevens are the hardest type to see through, since culture celebrates their defense" }, { letter: "C", text: "Accurate perception" }, { letter: "D", text: "Mental illness" }], answer: "B", explanation: "Naranjo observed that Seven optimism is the most socially invisible defense mechanism: culture rewards positivity, making the Seven's avoidance look like a virtue. 'Positive thinking' books are written by Sevens for Sevens — normalizing escapism as wisdom." },
  { id: 1122, type: 7, difficulty: 4 as 1|2|3|4|5, track1Day: 2, track2Day: 52, category: "Differential Diagnosis", question: "A person is fun-loving, scattered, and avoids negative emotions. Could be Seven or ADHD (or both). How to differentiate?", options: [{ letter: "A", text: "They're the same" }, { letter: "B", text: "Seven's scatteredness is emotionally driven — they shift away from pain toward pleasure; ADHD's scatteredness is neurologically driven — they struggle to sustain attention regardless of emotional valence" }, { letter: "C", text: "All Sevens have ADHD" }, { letter: "D", text: "ADHD people can't be Sevens" }], answer: "B", explanation: "Key test: does the distraction follow the pleasure-pain axis? If they focus beautifully on exciting things but scatter when it's boring or painful, that's more Seven. If they scatter even during things they love, that's more ADHD. And yes, many people are both." },
  { id: 1123, type: 7, difficulty: 4 as 1|2|3|4|5, track1Day: 3, track2Day: 53, category: "Shadow Work", question: "The Seven's relationship with grief is unique because:", options: [{ letter: "A", text: "They grieve easily" }, { letter: "B", text: "They may not grieve losses until years later — the reframing defense postpones grief so effectively that the Seven doesn't realize they haven't processed a loss until something breaks through the optimism" }, { letter: "C", text: "They never experience loss" }, { letter: "D", text: "Grief is a choice" }], answer: "B", explanation: "Sevens' delayed grief is legendary: they reframe a divorce as 'freedom,' a death as 'they're in a better place,' a job loss as 'a new chapter.' The grief gets stored, not processed. Years later, a small trigger can unleash the accumulated, unfelt losses — all at once." },
  { id: 1124, type: 7, difficulty: 4 as 1|2|3|4|5, track1Day: 4, track2Day: 54, category: "Growth Practices", question: "The practice of 'fasting' (from stimulation, not just food) benefits Sevens because:", options: [{ letter: "A", text: "They need to lose weight" }, { letter: "B", text: "It creates voluntary deprivation — the exact experience they've been fleeing — and reveals that they can survive without constant stimulation, weakening the panic response that drives their gluttony" }, { letter: "C", text: "It's trendy" }, { letter: "D", text: "It improves focus" }], answer: "B", explanation: "Stimulus fasting — no phone, no plans, no entertainment, no escape — confronts the Seven directly. The panic that arises ('I'm trapped in the present with nothing happening!') is exactly the panic they've been fleeing. Surviving it proves the fear was worse than the reality." },
  { id: 1125, type: 7, difficulty: 4 as 1|2|3|4|5, track1Day: 5, track2Day: 55, category: "Tritype Deep Dives", question: "The 713 tritype ('The Entrepreneur') combines:", options: [{ letter: "A", text: "Passive traits" }, { letter: "B", text: "Seven's vision with One's standards and Three's execution — creating a driven, optimistic achiever who combines creativity with discipline and results-orientation" }, { letter: "C", text: "Withdrawal and caution" }, { letter: "D", text: "Emotional sensitivity" }], answer: "B", explanation: "The 713 is the high-performance Seven: Seven provides the vision and enthusiasm, One adds standards and follow-through, and Three adds the drive to make it happen. This tritype actually finishes what it starts — the rare Seven who combines ideas with implementation." },
  { id: 1126, type: 7, difficulty: 4 as 1|2|3|4|5, track1Day: 6, track2Day: 56, category: "Spiritual Traditions", question: "The Seven's relationship with the Buddhist concept of 'dukkha' (suffering/unsatisfactoriness) is:", options: [{ letter: "A", text: "They agree easily" }, { letter: "B", text: "Direct confrontation — Buddhism's First Noble Truth ('Life is suffering') contradicts the Seven's entire worldview, making it either the most important or the most rejected teaching they encounter" }, { letter: "C", text: "Irrelevant" }, { letter: "D", text: "Identical to their current belief" }], answer: "B", explanation: "The Buddha's 'Life is suffering' is the Seven's worst nightmare spoken aloud. Their entire defense system was built to deny exactly this truth. But accepting dukkha is the beginning of the Seven's liberation — because only by acknowledging pain can they stop running from it." },
  { id: 1127, type: 7, difficulty: 4 as 1|2|3|4|5, track1Day: 7, track2Day: 57, category: "Attachment Style", question: "The Seven's 'pleasant avoidant' attachment style means:", options: [{ letter: "A", text: "They're securely attached" }, { letter: "B", text: "They appear warm and open but maintain emotional distance through constant activity, future-focus, and topic-switching — partners feel entertained but not truly intimate" }, { letter: "C", text: "They're cold and distant" }, { letter: "D", text: "They have no attachment style" }], answer: "B", explanation: "Sevens are the friendliest avoidants: they seem open, warm, and present. But emotional depth is deflected through humor, activity, and future-planning. Partners feel: 'We have so much fun, but I don't know if they really know me — or if I really know them.'" },
  { id: 1128, type: 7, difficulty: 4 as 1|2|3|4|5, track1Day: 8, track2Day: 58, category: "Parenting Style", question: "The Seven parent's greatest growth edge is:", options: [{ letter: "A", text: "Creating more fun experiences" }, { letter: "B", text: "Learning to sit with their child's pain without fixing or reframing it — allowing sadness, frustration, and disappointment to exist without converting them into positivity" }, { letter: "C", text: "Being more spontaneous" }, { letter: "D", text: "Having more adventures" }], answer: "B", explanation: "When a Seven's child is hurting, every cell in the parent screams: 'Fix it! Reframe it! Make it better!' The growth edge is resisting that urge: sitting with the crying child and saying 'I know this hurts' instead of 'But look at the bright side!'" },
  { id: 1129, type: 7, difficulty: 4 as 1|2|3|4|5, track1Day: 9, track2Day: 59, category: "Communication Style", question: "In therapy, Sevens often display what Naranjo called 'the seductive defense':", options: [{ letter: "A", text: "Sexual seduction" }, { letter: "B", text: "Using charm, humor, and entertaining stories to keep the session light and the therapist entertained — avoiding the deep, painful work by making therapy fun" }, { letter: "C", text: "Silence" }, { letter: "D", text: "Intellectual analysis" }], answer: "B", explanation: "Sevens can make therapy so entertaining that nothing therapeutic happens. They're wonderful storytellers, charming and funny — and a skilled therapist recognizes: 'You're performing for me to avoid going deeper.' The charm is the defense, and naming it is the breakthrough." },
  { id: 1130, type: 7, difficulty: 4 as 1|2|3|4|5, track1Day: 10, track2Day: 60, category: "Somatic Patterns", question: "The Seven's relationship with substance use is characterized by:", options: [{ letter: "A", text: "They never use substances" }, { letter: "B", text: "A higher risk for addictive patterns because substances provide the neurochemical shortcut to what Sevens seek: instant pleasure, pain avoidance, and expanded sensation — amplifying their natural defense in chemical form" }, { letter: "C", text: "Only using alcohol" }, { letter: "D", text: "Using substances for medical reasons" }], answer: "B", explanation: "Sevens are at elevated risk for addiction because substances do chemically what their psychology does cognitively: generate pleasure and avoid pain. Alcohol, stimulants, and psychedelics can become tools in the Seven's pain-avoidance toolkit, escalating the existing defense to dangerous levels." },
  // ── DIFFICULTY 5 (20 questions) ──
  { id: 1131, type: 7, difficulty: 5 as 1|2|3|4|5, track1Day: 41, track2Day: 91, category: "Ichazo Fixations", question: "Ichazo's concept of the Seven's 'trap' is 'idealism.' What does this mean?", options: [{ letter: "A", text: "They should be more realistic" }, { letter: "B", text: "The Seven believes that creating ideal conditions (the perfect plan, partner, lifestyle) will eliminate their anxiety — but idealism itself IS the anxiety, and no ideal future can satisfy a mind that can't rest in the present" }, { letter: "C", text: "Idealism is their strength" }, { letter: "D", text: "They should pursue their ideals more" }], answer: "B", explanation: "The trap: chasing the ideal experience feels like progress but is the problem itself. Each 'ideal' achieved reveals another ideal to pursue. The paradise is always 'almost here' — which means it's never here. Idealism is the carrot on the stick the Seven chases forever." },
  { id: 1132, type: 7, difficulty: 5 as 1|2|3|4|5, track1Day: 42, track2Day: 92, category: "Ichazo Fixations", question: "The Seven's virtue is 'Sobriety.' In the Enneagram sense, this means:", options: [{ letter: "A", text: "Not drinking alcohol" }, { letter: "B", text: "The ability to experience reality as it is — both pain and pleasure — without the intoxicating overlay of rationalization, reframing, and future-tripping that normally distorts their perception" }, { letter: "C", text: "Being serious" }, { letter: "D", text: "Giving up fun" }], answer: "B", explanation: "Sobriety for the Seven isn't about alcohol — it's about clear perception. When the reframing stops, the planning quiets, and the mind rests in what IS rather than what could be, the Seven sees reality directly. This sober vision reveals that unedited reality is actually more satisfying than the edited version." },
  { id: 1133, type: 7, difficulty: 5 as 1|2|3|4|5, track1Day: 43, track2Day: 93, category: "Object Relations Deep", question: "The Seven's 'manic defense' in object relations theory refers to:", options: [{ letter: "A", text: "Clinical mania" }, { letter: "B", text: "A defensive structure where the mind generates excitement, activity, and optimism specifically to ward off contact with depression, grief, and the despair that underlies the Seven's bright exterior" }, { letter: "C", text: "Being happy" }, { letter: "D", text: "Extreme exercise" }], answer: "B", explanation: "Klein's manic defense perfectly describes the Seven: a frantic positivity erected against depressive reality. The excitement isn't spontaneous joy — it's a defense against the grief waiting underneath. Every 'Isn't this fun?!' contains a hidden 'Please don't make me feel the sadness.'" },
  { id: 1134, type: 7, difficulty: 5 as 1|2|3|4|5, track1Day: 44, track2Day: 94, category: "Counter-Instinctual Combos", question: "An SO7 with a 6-wing (SO 7w6) can be confused with Type 2 because:", options: [{ letter: "A", text: "They're identical" }, { letter: "B", text: "The social instinct's group-service + Six-wing's loyalty + Seven's counter-type sacrifice creates someone who appears selflessly devoted to others' well-being — but the underlying driver is still avoiding their own inner pain" }, { letter: "C", text: "They look like Eights" }, { letter: "D", text: "They're antisocial" }], answer: "B", explanation: "SO 7w6 is the Seven who looks most like a Two: helpful, devoted, group-oriented, and apparently selfless. The key differentiator: ask what happens when the 'giving' is interrupted. A Two feels lost; the SO7 feels trapped — their 'giving' was an escape route from inner pain." },
  { id: 1135, type: 7, difficulty: 5 as 1|2|3|4|5, track1Day: 45, track2Day: 95, category: "Historical Enneagram", question: "The Seven's position between Six and Eight in the Enneagram reveals:", options: [{ letter: "A", text: "Nothing meaningful" }, { letter: "B", text: "The Seven is caught between the Six's fear and the Eight's power — wing toward Six and they become anxious pleasure-seekers; wing toward Eight and they become forceful vision-chasers" }, { letter: "C", text: "They should become a 6 or 8" }, { letter: "D", text: "It's numerically random" }], answer: "B", explanation: "The Seven's wings pull in opposite directions: the 6-wing adds anxiety, caution, and loyalty to the Seven's enthusiasm; the 8-wing adds assertiveness, power, and excess. 7w6 is the lighter, more collaborative Seven; 7w8 is the heavier, more forceful Seven." },
  { id: 1136, type: 7, difficulty: 5 as 1|2|3|4|5, track1Day: 46, track2Day: 96, category: "Integration/Disintegration Chains", question: "The complete Seven growth trajectory (7→5→8) reveals:", options: [{ letter: "A", text: "Random connections" }, { letter: "B", text: "A path from scattered stimulation (7) through focused depth (5) to embodied power (8) — the Seven must first learn to be still and go deep, then to engage with the full force of their being" }, { letter: "C", text: "A journey to more fun" }, { letter: "D", text: "A purely intellectual progression" }], answer: "B", explanation: "The 7→5→8 trajectory: scattered enthusiasm gains focus (Five) and then embodied power (Eight). The Seven who has done deep work can both envision AND implement, both dream AND act — their vision is no longer fantasy but grounded, powerful creative force." },
  { id: 1137, type: 7, difficulty: 5 as 1|2|3|4|5, track1Day: 47, track2Day: 97, category: "Naranjo's Character Types", question: "Naranjo's ultimate insight about the Seven's transformation is:", options: [{ letter: "A", text: "They need more fun" }, { letter: "B", text: "The Seven must discover that what they've been seeking through plans and experiences — wholeness, satisfaction, and peace — was available in the present moment all along, hidden by the very seeking that was supposed to find it" }, { letter: "C", text: "They should be more serious" }, { letter: "D", text: "Their optimism is always correct" }], answer: "B", explanation: "Naranjo's paradox for the Seven: the search IS the obstacle. The racing from experience to experience creates the very dissatisfaction it's trying to cure. When the Seven stops seeking and simply IS — fully present, fully here — they find that the present moment was always enough." },
  { id: 1138, type: 7, difficulty: 5 as 1|2|3|4|5, track1Day: 48, track2Day: 98, category: "Panel Wisdom", question: "Experienced Enneagram teachers note that the Seven's greatest contribution to the Enneagram community is:", options: [{ letter: "A", text: "Comic relief" }, { letter: "B", text: "Their embodiment of genuine joy — when a Seven does their work and finds real presence, they demonstrate that happiness without escapism is possible, and their joy becomes medicine rather than defense" }, { letter: "C", text: "Their organizational skills" }, { letter: "D", text: "Their seriousness" }], answer: "B", explanation: "A Seven who has done deep work is one of the most genuinely joyful beings on the planet. Their joy is no longer a defense — it's a direct expression of presence. This demonstrates to everyone that happiness isn't denial; it can be the most authentic response to fully experiencing life." },
  { id: 1139, type: 7, difficulty: 5 as 1|2|3|4|5, track1Day: 49, track2Day: 99, category: "Differential Diagnosis", question: "A creative, energetic person alternates between enthusiasm and dark moods. Could be Seven or bipolar. The differentiator:", options: [{ letter: "A", text: "They're the same" }, { letter: "B", text: "Seven mood shifts follow the pleasure-pain axis — enthusiasm is the defense, dark moods emerge when the defense fails; bipolar cycling is neurochemical and occurs independent of psychological triggers" }, { letter: "C", text: "Sevens don't have dark moods" }, { letter: "D", text: "Bipolar people can't be Sevens" }], answer: "B", explanation: "Seven mood swings have narrative logic: the high is the defense, the low appears when the defense fails (usually forced by loss or exhaustion). Bipolar swings can occur without precipitant. But again — a person can be both Seven and bipolar, and often the combination amplifies both patterns." },
  { id: 1140, type: 7, difficulty: 5 as 1|2|3|4|5, track1Day: 50, track2Day: 100, category: "Shadow Work", question: "The Seven's ultimate shadow work involves recognizing:", options: [{ letter: "A", text: "They need more experiences" }, { letter: "B", text: "That their optimism was built on a foundation of unfelt grief — and that the most courageous thing they can do is stop running, turn around, and face the pain they've been fleeing since childhood" }, { letter: "C", text: "That pain is an illusion" }, { letter: "D", text: "That they should be more positive" }], answer: "B", explanation: "The Seven's deepest work: turning around. After a lifetime of running forward — into plans, experiences, reframes — they turn to face what's behind them. The childhood pain, the accumulated grief, the losses they reframed away. This turn is the bravest thing a Seven can do." },
  { id: 1141, type: 7, difficulty: 5 as 1|2|3|4|5, track1Day: 1, track2Day: 51, category: "Growth Practices", question: "The Seven's equivalent of the Four's 'find beauty in the ordinary' is:", options: [{ letter: "A", text: "Plan better adventures" }, { letter: "B", text: "'Find sufficiency in the present' — discovering that this moment, without enhancement, addition, or escape, contains everything they need" }, { letter: "C", text: "Create more excitement" }, { letter: "D", text: "Join more groups" }], answer: "B", explanation: "The Seven's hardest practice: this moment is enough. Not 'this moment plus what's coming next.' Not 'this moment, which could be better if...' Just THIS. Plain, unenhanced, unplanned reality. When a Seven can rest here, they've found what they've been seeking everywhere else." },
  { id: 1142, type: 7, difficulty: 5 as 1|2|3|4|5, track1Day: 2, track2Day: 52, category: "Tritype Deep Dives", question: "The 752 tritype vs. the 794 tritype represent:", options: [{ letter: "A", text: "The same Seven" }, { letter: "B", text: "The 752 channels Seven energy into relational warmth (Two) and analytical depth (Five); the 794 channels it into peaceful creativity (Nine) and emotional authenticity (Four) — same core, different expressions" }, { letter: "C", text: "Identical behavioral patterns" }, { letter: "D", text: "Opposite types entirely" }], answer: "B", explanation: "752 is the cerebral-relational Seven: deep (Five), warm (Two), and broad (Seven). 794 is the creative-dreamy Seven: peaceful (Nine), authentic (Four), and enthusiastic (Seven). Both are Sevens, but one connects through knowledge and care, the other through beauty and presence." },
  { id: 1143, type: 7, difficulty: 5 as 1|2|3|4|5, track1Day: 3, track2Day: 53, category: "Spiritual Traditions", question: "The Seven's spiritual journey parallels the mythological archetype of:", options: [{ letter: "A", text: "The ruler" }, { letter: "B", text: "The Prodigal Son — the one who leaves home seeking excitement, exhausts themselves in indulgence, and finally returns to discover that what they were seeking was always at home" }, { letter: "C", text: "The warrior" }, { letter: "D", text: "The sage" }], answer: "B", explanation: "The Prodigal Son is the Seven's myth: leaving home (the present) for adventure (the future), spending everything (gluttony), hitting bottom (when defense fails), and returning home (to the present) where the feast (genuine satisfaction) was always waiting." },
  { id: 1144, type: 7, difficulty: 5 as 1|2|3|4|5, track1Day: 4, track2Day: 54, category: "Instinct x Wing Combos", question: "Rank the six Seven subtypes from most to least hedonistic:", options: [{ letter: "A", text: "All are the same" }, { letter: "B", text: "SP 7w8 (most hedonistic) → SP 7w6 → SX 7w8 → SX 7w6 → SO 7w8 → SO 7w6 (least hedonistic)" }, { letter: "C", text: "SO 7w6 is most hedonistic" }, { letter: "D", text: "Rankings can't be determined" }], answer: "B", explanation: "SP instinct maximizes sensory pleasure; the 8-wing adds excess and force. SP 7w8 is the most indulgent Seven: powerful appetite + physical focus = maximum hedonism. SO 7w6 is the most counter-typical: social sacrifice + loyal caution = the 'selfless' Seven who barely looks Seven." },
  { id: 1145, type: 7, difficulty: 5 as 1|2|3|4|5, track1Day: 5, track2Day: 55, category: "Panel Wisdom", question: "Mature Sevens report that their relationship with joy changed from:", options: [{ letter: "A", text: "Less joy to more" }, { letter: "B", text: "Manic, desperate, and fleeting to quiet, deep, and sustainable — joy that comes from presence rather than pursuit, requiring nothing external to trigger it" }, { letter: "C", text: "More joy to less" }, { letter: "D", text: "Joy stayed the same" }], answer: "B", explanation: "The Seven's joy evolution: from frantic (chased) to grounded (rested in). Young Seven joy is loud, urgent, and dependent on stimulation. Mature Seven joy is quiet, deep, and self-arising — the difference between a sugar rush and the warmth of a good meal." },
  { id: 1146, type: 7, difficulty: 5 as 1|2|3|4|5, track1Day: 6, track2Day: 56, category: "Historical Enneagram", question: "Epicurus, often misunderstood as a hedonist, actually taught a philosophy that represents:", options: [{ letter: "A", text: "Pure Seven indulgence" }, { letter: "B", text: "Healthy Seven integration — he advocated for simple pleasures, friendship, and freedom from anxiety through moderation and presence, not through excess and stimulation-seeking" }, { letter: "C", text: "Anti-Seven philosophy" }, { letter: "D", text: "Asceticism" }], answer: "B", explanation: "Epicurus has been misread as a hedonist, but his actual philosophy — simple pleasures, friendship, presence, freedom from anxiety — describes a Seven who has done their work. He found that less stimulation, fully experienced, brought more satisfaction than more stimulation, briefly sampled." },
  { id: 1147, type: 7, difficulty: 5 as 1|2|3|4|5, track1Day: 7, track2Day: 57, category: "Naranjo's Character Types", question: "Naranjo observed that the Seven's 'intellectualization of emotion' creates:", options: [{ letter: "A", text: "Better emotional intelligence" }, { letter: "B", text: "A person who can articulate their emotional patterns perfectly while being completely disconnected from feeling them — they know about feelings without feeling them" }, { letter: "C", text: "Total emotional numbness" }, { letter: "D", text: "Authentic emotional depth" }], answer: "B", explanation: "Sevens can describe their emotional patterns with impressive accuracy: 'I know I avoid grief because my mother left when I was seven.' But describing the pattern is not feeling it. The Seven can narrate their avoidance while actively avoiding — making the insight itself a new form of escape." },
  { id: 1148, type: 7, difficulty: 5 as 1|2|3|4|5, track1Day: 8, track2Day: 58, category: "Differential Diagnosis", question: "How do you distinguish a healthy Seven (genuinely joyful) from an unhealthy Seven (defensively positive)?", options: [{ letter: "A", text: "You can't" }, { letter: "B", text: "The healthy Seven can sit with pain — they don't reframe it, escape it, or rush past it; the unhealthy Seven cannot tolerate unpleasant states and must immediately convert them into something positive" }, { letter: "C", text: "Healthy Sevens are less fun" }, { letter: "D", text: "Unhealthy Sevens are sadder" }], answer: "B", explanation: "The test: can they stay with pain? A healthy Seven says 'This is terrible' and sits in it. An unhealthy Seven says 'This is terrible, BUT look at the silver lining!' The ability to tolerate unpleasant states without reframing them is the hallmark of Seven health." },
  { id: 1149, type: 7, difficulty: 5 as 1|2|3|4|5, track1Day: 9, track2Day: 59, category: "Relationship Dynamics", question: "The Seven's ultimate relational breakthrough is:", options: [{ letter: "A", text: "Finding the perfect partner" }, { letter: "B", text: "Discovering that the depth of commitment — choosing one person and staying through the boring, painful, ordinary middle — creates a richer joy than any new-relationship high ever could" }, { letter: "C", text: "Having more partners" }, { letter: "D", text: "Finding a partner who's always exciting" }], answer: "B", explanation: "The Seven's relational liberation: monogamous depth surpasses polyamorous breadth. Staying with one person through the unglamorous middle — and finding that the deepening intimacy of year 15 surpasses the thrill of month 3 — is the Seven's most courageous relationship act." },
  { id: 1150, type: 7, difficulty: 5 as 1|2|3|4|5, track1Day: 10, track2Day: 60, category: "Growth Practices", question: "The practice that represents the Seven's complete liberation is:", options: [{ letter: "A", text: "Having every experience possible" }, { letter: "B", text: "Sitting in an empty room with nothing to do, nowhere to go, and no plan — and finding it not just tolerable but deeply satisfying" }, { letter: "C", text: "Making a perfect plan" }, { letter: "D", text: "Traveling the world" }], answer: "B", explanation: "The liberated Seven can do what once seemed impossible: sit in an empty room and feel complete. No plans needed. No stimulation required. No escape necessary. The present moment — plain, quiet, and unadorned — is enough. This is the Seven's enlightenment: finding paradise in the ordinary." },
];
